fn verify_transaction(tx: &Transaction) -> Option<VerificationResult> {
    if let Some(amount_check) = (tx.amount > 10000.0).then(|| {
        VerificationResult {
            is_fraudulent: true,
            reason: "High-value transaction".into(),
        }
    }) {
        return Some(amount_check);
    }

    if let Some(country_check) = (!["US", "CA", "GB"].contains(&tx.country.as_str())).then(|| {
        VerificationResult {
            is_fraudulent: true,
            reason: format!("Unusual country: {}", tx.country),
        }
    }) {
        return Some(country_check);
    }

    None
}

async fn process_transaction(tx: Transaction, alert_sender: mpsc::Sender<String>) {
    info!("Processing transaction: {:?}", tx);

    if let Some(verification) = verify_transaction(&tx) {
        warn!("Potential fraud detected: {:?}", verification);
        let alert_msg = format!("Fraud alert - User: {}, Reason: {}", tx.user_id, verification.reason);
        tokio::spawn(async move {
            let _ = alert_sender.send(alert_msg).await;
        });
    } else {
        info!("Transaction processed normally: {}", tx.user_id);
    }
}

async fn send_alert(mut receiver: mpsc::Receiver<String>) {
    while let Some(alert) = receiver.recv().await {
        // Implement actual alert integration (email/webhook/etc)
        warn!("ALERT TRIGGERED: {}", alert);
    }
}

