async fn main() -> Result<(), Box<dyn std::error::Error>> {
    tracing_subscriber::fmt::init();

    let nats_conn = async_nats::connect("nats://localhost:4222").await?;
    let subscription = nats_conn.subscribe("transactions").await?;

    let (alert_tx, alert_rx) = mpsc::channel(100);
    tokio::spawn(send_alert(alert_rx));

    while let Some(message) = subscription.next().await {
        if let Ok(tx) = serde_json::from_slice::<Transaction>(&message.data) {
            let sender = alert_tx.clone();
            tokio::spawn(process_transaction(tx, sender));
        }
    }

    Ok(())
