data class ApiResponse(val success: Boolean, val data: String?, val error: String?)

data class UserData(
    @SerializedName("username") val username: String,
    @SerializedName("email") val email: String
)

data class PostData(
    @SerializedName("title") val title: String,
    @SerializedName("body") val body: String
)

val userProcessor: (String) -> String = { json ->
    val data = json.fromJson<UserData>()
    "${data.username} (${data.email})"
}

val postProcessor: (String) -> String = { json ->
    val data = json.fromJson<PostData>()
    "\"${data.title}\" - ${data.body.take(20)}..."
