        install(ContentNegotiation) { gson() }
        routing {
            get("/") {
                val apis = listOf(
                    "https://api.example.com/users/1" to userProcessor,
                    "https://api.example.com/posts/1" to postProcessor
                )

                val results = CoroutineScope(Dispatchers.IO).async {
