use std::collections::HashMap;
use std::sync::{Arc, Mutex};

type RouteHandler = Box<dyn Fn() -> String + Send + Sync + 'static>;

async fn handle_request(
    path: web::Path<String>,
    routes: web::Data<Arc<Mutex<HashMap<String, RouteHandler>>>>,
) -> impl Responder {
    let routes = routes.lock().unwrap();
    let full_path = format!("/{}", path);
    match routes.get(&full_path) {
        Some(handler) => HttpResponse::Ok().content_type("text/html").body(handler()),
        None => HttpResponse::NotFound().body("Page not found"),
    }
}

