        "/home".to_string(),
        Box::new(|| "<html><body><h1>Home Page</h1></body></html>".to_string()),
    );
    routes.insert(
        "/about".to_string(),
        Box::new(|| "<html><body><h1>About Us</h1></body></html>".to_string()),
