def main():
    allowed_methods = {'GET', 'POST', 'PUT', 'DELETE'}
    http_methods = defaultdict(lambda: {'total': 0, 'ips': []})

    with open('access.log', 'r') as file:
        for line in file:
            match = re.match(r'^(\S+).*?"(GET|POST|PUT|DELETE|HEAD|OPTIONS|PATCH|TRACE)\s+', line.strip())
            if match:
                ip, method = match.groups()
                method = method.upper()
                if method in allowed_methods:
                    http_methods[method]['ips'].append(ip)
                    http_methods[method]['total'] += 1

    for method in allowed_methods:
        unique_ips = {ip for ip in http_methods[method]['ips']}
        http_methods[method]['unique'] = len(unique_ips)

    for method in ['GET', 'POST', 'PUT', 'DELETE']:
        data = http_methods[method]
        print(f"{method}: {data['unique']} unique IPs, {data['total']} total requests")

