package main

import (
	"crypto/aes"
	"crypto/cipher"
	"crypto/rand"
	"io"
	"log"
	"os"
	"path/filepath"
)

type EncryptionResult struct {
	File  string
	Error error
}

func main() {
	dir := "./testdata"
	entries, err := os.ReadDir(dir)
	if err != nil {
		log.Fatal(err)
	}

	var files []string
	for _, e := range entries {
		if !e.IsDir() {
			files = append(files, filepath.Join(dir, e.Name()))
		}
	}

	key := make([]byte, 32)
	if _, err := rand.Read(key); err != nil {
		log.Fatal(err)
	}

	resChan := make(chan EncryptionResult)

	for _, file := range files {
		go encryptFile(file, key, resChan)
	}

	for i := 0; i < len(files); i++ {
		res := <-resChan
		if res.Error != nil {
			log.Printf("Failed %s: %v", res.File, res.Error)
		} else {
			log.Printf("Encrypted %s", res.File)
		}
	}
}

func encryptFile(path string, key []byte, resChan chan<- EncryptionResult) {
	data, err := os.ReadFile(path)
	if err != nil {
		resChan <- EncryptionResult{path, err}
		return
	}

	block, err := aes.NewCipher(key)
	if err != nil {
		resChan <- EncryptionResult{path, err}
		return
	}

	gcm, err := cipher.NewGCM(block)
	if err != nil {
		resChan <- EncryptionResult{path, err}
		return
	}

	nonce := make([]byte, gcm.NonceSize())
	if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
		resChan <- EncryptionResult{path, err}
		return
	}

	encryptedData := gcm.Seal(nonce, nonce, data, nil)
	dest := path + ".encrypted"
	if err := os.WriteFile(dest, encryptedData, 0644); err != nil {
		resChan <- EncryptionResult{path, err}
		return
	}

	resChan <- EncryptionResult{path, nil}
}
