package main

import (
    "database/sql"
    "encoding/json"
    "net/http"
    "strconv"
    "github.com/gorilla/mux"
    _ "github.com/mattn/go-sqlite3"
)

type Book struct {
    ID       int    `json:"id"`
    Title    string `json:"title"`
    Author   string `json:"author"`
    Quantity int    `json:"quantity"`
}

func main() {
    db, err := sql.Open("sqlite3", "./books.db")
    if err != nil {
        panic(err)
    }
    defer db.Close()

    _, err = db.Exec("CREATE TABLE IF NOT EXISTS books (id INTEGER PRIMARY KEY, title TEXT, author TEXT, quantity INTEGER)")
    if err != nil {
        panic(err)
    }

    router := mux.NewRouter()
    router.HandleFunc("/books", booksHandler).Methods("GET", "POST")
    router.HandleFunc("/books/{id}", bookHandler).Methods("GET", "PUT", "DELETE")

    http.ListenAndServe(":8080", router)
}

func booksHandler(w http.ResponseWriter, r *http.Request) {
    db, err := sql.Open("sqlite3", "./books.db")
    if err != nil {
        http.Error(w, err.Error(), http.StatusInternalServerError)
        return
    }
    defer db.Close()

    switch r.Method {
    case "GET":
        rows, err := db.Query("SELECT id, title, author, quantity FROM books")
        if err != nil {
            http.Error(w, err.Error(), http.StatusInternalServerError)
            return
        }
        defer rows.Close()

        var books []Book
        for rows.Next() {
            var b Book
            err = rows.Scan(&b.ID, &b.Title, &b.Author, &b.Quantity)
            if err != nil {
                http.Error(w, err.Error(), http.StatusInternalServerError)
                return
            }
            books = append(books, b)
        }
        json.NewEncoder(w).Encode(books)

    case "POST":
        var b Book
        err := json.NewDecoder(r.Body).Decode(&b)
        if err != nil {
            http.Error(w, err.Error(), http.StatusBadRequest)
            return
        }

        res, err := db.Exec("INSERT INTO books (title, author, quantity) VALUES (?, ?, ?)", b.Title, b.Author, b.Quantity)
        if err != nil {
            http.Error(w, err.Error(), http.StatusInternalServerError)
            return
        }
        id, _ := res.LastInsertId()
        b.ID = int(id)
        json.NewEncoder(w).Encode(b)
    }
}

func bookHandler(w http.ResponseWriter, r *http.Request) {
    db, err := sql.Open("sqlite3", "./books.db")
    if err != nil {
        http.Error(w, err.Error(), http.StatusInternalServerError)
        return
    }
    defer db.Close()

    vars := mux.Vars(r)
    id, _ := strconv.Atoi(vars["id"])

    switch r.Method {
    case "GET":
        var b Book
        err := db.QueryRow("SELECT id, title, author, quantity FROM books WHERE id = ?", id).Scan(&b.ID, &b.Title, &b.Author, &b.Quantity)
        if err != nil {
            http.Error(w, err.Error(), http.StatusNotFound)
            return
        }
        json.NewEncoder(w).Encode(b)

    case "PUT":
        var b Book
        err := json.NewDecoder(r.Body).Decode(&b)
        if err != nil {
            http.Error(w, err.Error(), http.StatusBadRequest)
            return
        }

        _, err = db.Exec("UPDATE books SET title = ?, author = ?, quantity = ? WHERE id = ?", b.Title, b.Author, b.Quantity, id)
        if err != nil {
            http.Error(w, err.Error(), http.StatusInternalServerError)
            return
        }
        b.ID = id
        json.NewEncoder(w).Encode(b)

    case "DELETE":
        _, err := db.Exec("DELETE FROM books WHERE id = ?", id)
        if err != nil {
            http.Error(w, err.Error(), http.StatusInternalServerError)
            return
        }
        w.WriteHeader(http.StatusNoContent)
    }
}
