package main

import (
	"fmt"
	"math/rand"
	"net"
	"sync"
	"time"
)

type User struct {
	ID    int
	Name  string
	Valid bool
}

type Result struct {
	Status string
}

var (
	aggregate struct {
		success int
		failure int
		mutex   sync.Mutex
	}
)

func main() {
	rand.Seed(time.Now().UnixNano())
	listener, _ := net.Listen("tcp", ":8080")
	defer listener.Close()

	for {
		conn, _ := listener.Accept()
		go handleConn(conn)
	}
}

func handleConn(conn net.Conn) {
	defer conn.Close()
	fetchChan := make(chan User)
	processChan := make(chan Result)

	go fetchUser(fetchChan)
	go processUser(fetchChan, processChan)

	result := <-processChan
	conn.Write([]byte(result.Status))
}

func fetchUser(ch chan<- User) {
	time.Sleep(time.Duration(rand.Intn(100)) * time.Millisecond)
	ch <- User{
		ID:    rand.Intn(1000),
		Name:  fmt.Sprintf("User%d", rand.Intn(1000)),
		Valid: rand.Intn(2) == 1,
	}
	close(ch)
}

func processUser(fetchCh <-chan User, resultCh chan<- Result) {
	user := <-fetchCh
	status := "OK: User processed successfully"
	if !user.Valid {
		status = "ERROR: Invalid user data"
	}

	aggregate.mutex.Lock()
	if user.Valid {
		aggregate.success++
	} else {
		aggregate.failure++
	}
	aggregate.mutex.Unlock()

	resultCh <- Result{Status: status}
	close(resultCh)
}
