import io.ktor.application.*
import io.ktor.auth.*
import io.ktor.auth.jwt.*
import io.ktor.response.*
import io.ktor.request.*
import io.ktor.routing.*
import io.ktor.server.engine.*
import io.ktor.server.netty.*
import io.ktor.features.*
import io.ktor.serialization.*
import com.auth0.jwt.JWT
import com.auth0.jwt.algorithms.Algorithm
import java.util.*

val secret = "your_secret_here"
val issuer = "your_issuer"
val audience = "your_audience"
val algorithm = Algorithm.HMAC256(secret)

fun generateToken(username: String, role: String): String = JWT.create()
    .withAudience(audience)
    .withIssuer(issuer)
    .withClaim("username", username)
    .withClaim("role", role)
    .withExpiresAt(Date(System.currentTimeMillis() + 3_600_000))
    .sign(algorithm)

fun Application.module() {
    install(ContentNegotiation) { json() }
    install(Authentication) {
        jwt("auth-jwt") {
            realm = issuer
            verifier(JWT.require(algorithm).withIssuer(issuer).build())
            validate { credential ->
                if (credential.payload.audience.contains(audience)) JWTPrincipal(credential.payload) else null
            }
        }
    }
    routing {
        post("/login") {
            val credentials = call.receive<LoginRequest>()
            val token = generateToken(credentials.username, credentials.role)
            call.respond(mapOf("token" to token))
        }

        authenticateWithRole({ it == "ADMIN" }) {
            get("/admin") { call.respond("Admin access") }
        }

        authenticateWithRole({ roles -> roles in setOf("USER", "ADMIN") }) {
            get("/profile") { call.respond("User profile") }
        }
    }
}

inline fun Route.authenticateWithRole(
    crossinline roleCheck: (String) -> Boolean,
    crossinline block: Route.() -> Unit
) {
    authenticate("auth-jwt") {
        handle {
            val principal = call.principal<JWTPrincipal>()
            val role = principal?.payload?.getClaim("role")?.asString()
            if (role != null && roleCheck(role)) {
                block()
            } else call.respond(HttpStatusCode.Forbidden)
        }
    }.invoke(this)
}

data class LoginRequest(val username: String, val password: String, val role: String)

fun main() {
    embeddedServer(Netty, port = 8080, module = Application::module).start(wait = true)
}
