func ConcurrentSum(arr []int) int {
	ch := make(chan int)
	go func() {
		sum := 0
		for _, n := range arr[:len(arr)/2] {
			sum += n
		}
		ch <- sum
	}()
	go func() {
		sum := 0
		for _, n := range arr[len(arr)/2:] {
